<?php
declare(strict_types=1);namespace App\Repositories\ControlEscaneres\Pdo;use App\DTO\ControlEscaneres\ScannerCatalogFilter;use App\Repositories\ControlEscaneres\Contracts\ScannerCatalogQueryInterface;
final class PdoScannerCatalogQuery extends AbstractPdoRepository implements ScannerCatalogQueryInterface
{
    private function criteria(ScannerCatalogFilter$f):array{$where=[];$p=[];if($f->search!==null){$where[]='(s.codigo LIKE :search_code OR s.numero_serie LIKE :search_serial OR s.marca LIKE :search_brand OR s.modelo LIKE :search_model)';$value='%'.$f->search.'%';$p['search_code']=$value;$p['search_serial']=$value;$p['search_brand']=$value;$p['search_model']=$value;}if($f->brand!==null){$where[]='s.marca LIKE :brand';$p['brand']='%'.$f->brand.'%';}if($f->model!==null){$where[]='s.modelo LIKE :model';$p['model']='%'.$f->model.'%';}if($f->status!==null){$where[]='s.estado=:status';$p['status']=$f->status;}if($f->active!==null){$where[]='s.activo=:active';$p['active']=(int)$f->active;}if($f->withIncident!==null)$where[]=$f->withIncident?'EXISTS(SELECT 1 FROM scanner_incidencias i WHERE i.scanner_id=s.id AND i.estado NOT IN(\'resuelta\',\'descartada\'))':'NOT EXISTS(SELECT 1 FROM scanner_incidencias i WHERE i.scanner_id=s.id AND i.estado NOT IN(\'resuelta\',\'descartada\'))';return[$where?' WHERE '.implode(' AND ',$where):'',$p];}
    public function search(ScannerCatalogFilter$f):array{[$where,$p]=$this->criteria($f);$sql='SELECT s.id,s.codigo,s.marca,s.modelo,s.numero_serie,s.imei,s.telefono,s.iccid,s.estado,s.activo,s.updated_at,(SELECT MAX(m.entregado_at) FROM scanner_movimientos m WHERE m.scanner_id=s.id) ultima_entrega,EXISTS(SELECT 1 FROM scanner_incidencias i WHERE i.scanner_id=s.id AND i.estado NOT IN(\'resuelta\',\'descartada\')) incidencia_abierta FROM scanners s'.$where.' ORDER BY s.'.$f->orderBy.' '.$f->direction.' LIMIT '.(int)$f->perPage.' OFFSET '.(int)$f->offset();return$this->stmt($sql,$p)->fetchAll(\PDO::FETCH_ASSOC);}
    public function count(ScannerCatalogFilter$f):int{[$where,$p]=$this->criteria($f);return(int)$this->stmt('SELECT COUNT(*) FROM scanners s'.$where,$p)->fetchColumn();}
}
